var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드에서도 많은 일이 있었던 모양이군.","JPN":"シャレードでも色々あったようだな。","ENG":"It seems a great deal happened in Charade as well.","TWN":"看來在查雷德也發生了不少事呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"……일단은 보고한 대로야.","JPN":"……とりあえず、報告したとおりだ。","ENG":"...For now, it's just as I reported.","TWN":"……總之，和報告的一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"프론트 베이에서 인계 받았던 선로전환기는 파괴되었고. 유산은 소실되었어.","JPN":"フロントベイから引き渡された線路転換器は破壊され、遺産は消失した。","ENG":"The Track Switcher we received from Front Bay was destroyed, and the Legacy was lost.","TWN":"在前灣交接的線路轉換器被破壞，遺產也已下落不明。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"유산을 분실한 이상, 다음 도시에서는 전환기의 도움을 받을 수 없겠지.","JPN":"遺産を失った以上、次の都市では転換器の力を借りることはできない。","ENG":"With the Legacy gone, we won't be able to rely on the Switcher in the next city.","TWN":"既然遺產遺失，在下一座城市也無法再借助轉換器的力量了吧。"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어차피 전조 현상이 발생한 순간부터 예정된 일이었어.","JPN":"どのみち、前兆現象が発生した瞬間から決まっていた結果だ。","ENG":"It was inevitable from the moment the omen phenomenon began.","TWN":"反正從前兆現象發生的那一刻起，這一切就已經注定好了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그나마 황금향의 유산이 있었기에 조금이나마 시간을 벌 수 있었던 것이겠지.","JPN":"それでも黄金郷の遺産があったから、少しでも時間を稼げたんだ。","ENG":"At least the Golden Vale's Legacy bought us a little time.","TWN":"但至少因為黃金鄉的遺產，我們才爭取到一點時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그로 인해, 우리는 많은 사람들을 구할 수 있었어.","JPN":"おかげで我々は多くの人を助けることができた。","ENG":"Because of that, we were able to save many lives.","TWN":"也因此救了許多人。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 다음 도시에 대한 안배도 이미 마쳐두었네.","JPN":"そして、次の都市のための布石もすでに打ってある。","ENG":"And preparations for the next city are already complete.","TWN":"而且也已經完成對下座城市的安排了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"최고 관리자…….","JPN":"最高管理者……","ENG":"Supreme Administrator...","TWN":"最高管理者……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"우리 관리국에게 승산이 있을까?","JPN":"私たち管理局に勝ち目はあるだろうか？","ENG":"Do we really stand a chance?","TWN":"我們管理局真的還有勝算嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드에는 S급 카운터가 셋이나 있었어. 그 외 전력들도 충분히 강했지.","JPN":"シャレードにはS級カウンターが3人もいた。他の戦力も皆十分に強かった。","ENG":"There were three Grade S Counters in Charade, and the rest of our forces were strong as well.","TWN":"查雷德有三名S級制裁者，其餘戰力也相當充足。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 준비해둔 재난 대응 매뉴얼도 손색이 없었어.","JPN":"リヒャルトが用意しておいた災害対応マニュアルも、非の打ち所がなかった。","ENG":"The disaster response manual Richard prepared was also flawless.","TWN":"理查準備的災害應對手冊也沒有缺點。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"모든 조건이 최선이었는데도…….","JPN":"どれも最高の条件だったにもかかわらず……","ENG":"Every condition was ideal, and yet...","TWN":"所有條件都已經是最佳情況了……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"결국 우리는 그 무엇도 막아내지 못했잖아?","JPN":"結局私たちは何も止められなかったじゃないか。","ENG":"In the end, we couldn't stop anything.","TWN":"可是最終我們什麼都阻止不了，不是嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"피할 수 없는 침식 재난 앞에서, 우리가 정말로 무언가를 바꿀 수 있을까?","JPN":"避けられない侵食災害の前で、私たちは本当に、何かを変えられるのか？","ENG":"Faced with an unavoidable Corruption disaster, can we truly change anything?","TWN":"面對無法逃避的侵蝕災害，我們真的能改變什麼嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"글쎄, 하지만 마지막까지 노력해 봐야지.","JPN":"そうだな、でも最後までもがいてみないとな。","ENG":"Who knows. But we have to try until the very end.","TWN":"誰知道呢？但我們還是得努力到最後。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설령, 그것이 누군가에 의해 철저히 만들어진 기적이라고 할지라도 말이야.","JPN":"たとえそれが、誰かによって徹底的に作られた奇跡だとしても。","ENG":"Even if that hope is nothing more than a miracle meticulously manufactured by someone.","TWN":"即便那是一場徹底被某人安排好的奇蹟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"만들어진 기적이라고……?","JPN":"作られた奇跡……？","ENG":"A manufactured miracle...?","TWN":"被安排好的奇蹟……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자자, 너무 나쁜 쪽만 보지 말고, 좋게 생각하자고~","JPN":"ささ、あまりネガティブに考えず、ポジティブに行きましょう～","ENG":"Now, now, let's not dwell only on the worst-case scenario. Let's look at the bright side.","TWN":"好了，別老往壞處想，往好的一面看嘛～"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"샤레이드를 뒤덮은 뿌리 때문에 도시 대부분의 기능은 마비되었지만.","JPN":"シャレードを覆った根のせいで都市の機能はほとんど麻痺したけど。","ENG":"Most city functions were paralyzed by the roots covering Charade, but...","TWN":"雖然城市大部分機能都因為覆蓋查雷德的根癱瘓了，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"95% 이상의 시민권자들이 안전 쉘터로 대피를 마쳤어.","JPN":"95％以上の市民権者が安全シェルターに避難できたわ。","ENG":"Over 95% of registered citizens have already evacuated to safe shelters.","TWN":"但95%以上的市民都已撤離到安全庇護所。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 외 거주민들도 조디악 나이츠의 함선을 이용하여 피난 중이고.","JPN":"その他の居住民も、ゾディアックナイツの艦船に乗って避難しているし。","ENG":"The remaining residents are evacuating using Zodiac Knights ships.","TWN":"其餘居民也正搭乘十二宮騎士團的艦船撤離中。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"리하르트의 매뉴얼대로라면, 물과 식량도 30일까지는 비축분이 있을 거야.","JPN":"リヒャルトのマニュアル通りなら、水や食糧も30日分は備蓄分があるはずよ。","ENG":"According to Richard's manual, we have enough water and food stockpiled for thirty days.","TWN":"依照理查的手冊，水與糧食的儲備量至少還能撐30天。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 이 정도면, 그럭저럭 괜찮은 결과 아닐까?","JPN":"この程度ならまあまあいい結果じゃない？","ENG":"Well, all things considered, isn't that a fairly decent outcome?","TWN":"這樣的結果算還可以吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"공인 카운터인 자네와 조디악 나이츠가 힘써준 덕분이겠지.","JPN":"公認カウンターである君とゾディアックナイツが力を尽くしてくれたおかげだ。","ENG":"That's thanks to you as an Official Counter, and to the efforts of the Zodiac Knights.","TWN":"這都是多虧了你這位認證制裁者，以及十二宮騎士團的努力吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"과찬입니다, 최고 관리자.","JPN":"もったいないお言葉です、最高管理者。","ENG":"You flatter me, Supreme Administrator.","TWN":"你過獎了，最高管理者。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"저희 기사단은 늘 그렇듯, 민중을 위해서 해야 할 일을 했을 뿐이니까요.","JPN":"私たち騎士団はいつものように、民衆のためにやるべきことをしたまでです。","ENG":"We only did what needed to be done to protect the people.","TWN":"我們騎士團一如既往，只是做了該為民眾做的事而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하지만 한 가지 신경 쓰이는 사람이 있습니다.","JPN":"ですが一人、気になる人がいます。","ENG":"However, there is one person who concerns me.","TWN":"不過，有一個人讓我有些在意。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 누구지?","JPN":"誰かね？","ENG":"Who might that be?","TWN":"那是誰呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이름은 모릅니다. 냉철하고 차가운 분위기의 여성이었죠.","JPN":"名前は知りません。落ち着いていて冷たい雰囲気の女性でした。","ENG":"I don't know her name. She was a woman with a calm, cold demeanor.","TWN":"我不知道她的名字，是一位冷靜又冷漠的女性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"상황은 잘 모르지만, 그녀가 없었다면 우리는 전부 무사하지 못했겠죠.","JPN":"事情は詳しく知りませんが、彼女がいなかったら私たちは皆無事では済まなかったでしょう。","ENG":"I don't know the full circumstances, but without her, none of us would have survived.","TWN":"雖然我不清楚詳細情況，但如果沒有她，我們恐怕無一能倖免。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"하지만 어째선지 그녀는 관리국이 제공하는 피난선에 오르지 않았어요.","JPN":"ですが、なぜか彼女は管理局が提供する艦船に搭乗しませんでした。","ENG":"Yet for some reason, she did not board the evacuation ship provided by the Administration.","TWN":"然而不知為何，她沒有登上管理局提供的撤離船。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"추측컨대 아직 샤레이드에 남아있는 것 같은데…….","JPN":"おそらく、まだシャレードに残っていると思われますが……","ENG":"From what I can tell, she seems to still be in Charade...","TWN":"我推測她應該仍留在查雷德……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그녀의 행방이 걱정되는군요.","JPN":"彼女の行方が心配です。","ENG":"I'm worried about her whereabouts.","TWN":"她的去向實在令人擔心。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"마침내 제 차례가 된 모양이로군요.","JPN":"やっと私の番のようですわね。","ENG":"It seems it's finally my turn.","TWN":"看來終於輪到我了呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"기다리고 있었어요, 사장님.","JPN":"お待ちしておりましたわ、社長。","ENG":"I've been waiting, Boss.","TWN":"我一直在等你，老闆。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"자네에게 또 신세를 지고 말았군, 맥크레디 양","JPN":"君にはまた世話になってしまったな、マクレディー君。","ENG":"I find myself indebted to you once again, MacCready.","TWN":"又欠你一個人情了呢，麥克蕾蒂小姐。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이 기계새가 다시 영지에 날아왔을 때부터 짐작하고 있던 일이었습니다.","JPN":"この機械の鳥が再び領地に舞い降りてきた時から、予想はしておりました。","ENG":"I suspected as much the moment that machine bird returned to my estate.","TWN":"從這隻機器鳥又飛回領地時，我就已經猜到了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"학회장으로서 당연히 짊어져야 하는 일이기도 하고요.","JPN":"学会長として当然負うべきことでもありますし。","ENG":"It was a burden I was always meant to bear as President.","TWN":"這也是身為學會長理應承擔的責任。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네에게는 늘 고맙게 생각해.","JPN":"……君にはいつも、助けられてばかりさ。","ENG":"I'm always grateful to you.","TWN":"我一直都很感激你。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전조 현상이 가속하여, 제6종 침식체가 이 세계에 모습을 드러냈을 때.","JPN":"前兆現象が加速し、第6種侵食体がこの世界に現れた時……","ENG":"When the omen phenomenon accelerated and the Category 6 C.O. manifested in this world...","TWN":"當前兆現象加速、第6類侵蝕體出現在這個世界時，"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이 때만큼은 관리자로서 고를 수 있는 선택지가 별로 없었다네.","JPN":"あんな事態では、管理者として選べる選択肢があまりなくてね。","ENG":"There were very few choices I could make as Administrator.","TWN":"身為管理者，我能選擇的選項其實並不多。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"허신 정도의 침식체를 단독으로 토벌할 수 있는 인원은 무척 한정되어 있으니까.","JPN":"虚神ほどの侵食体を単独で討伐できる者は、極めて少ない。","ENG":"Those capable of single-handedly subjugating a C.O. like the Hollow God are extremely limited.","TWN":"能夠單獨討伐虛神等級侵蝕體的人員，本就極為有限。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네가 이미 큰 짐을 지고 있다는 건, 알고 있었지만…….","JPN":"君がすでに重荷を背負っていることは承知している……","ENG":"I knew you were already carrying a heavy burden...","TWN":"我知道你已經背負了很沉重的負擔……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼에도 자네에게 부탁할 수밖에 없었네.","JPN":"それでも、君に頼るしかなかった。","ENG":"But even so, I had no choice but to ask you.","TWN":"但即便如此，我還是只能拜託你。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"교단과의 마찰도 잘 해결해주었어. 자네가 없었다면, 많은 사상자가 발생했을 거야.","JPN":"教団との衝突も、君がいなければより多くの死傷者が出ていただろう。","ENG":"You also resolved the friction with the faction admirably. Without you, there would have been many casualties.","TWN":"你也妥善解決了與教團的摩擦。若沒有你，必然會出現大量傷亡。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네에게는 항상 감사히 생각하고 있다네. ","JPN":"君には、心から感謝している。","ENG":"I am always thankful to you.","TWN":"我一直都心懷感激。 "},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니까 너무 그렇게 침울해하지 말게.","JPN":"だからそう落ち込まないでくれ。","ENG":"So please, don't look so dejected.","TWN":"所以別那麼消沉了。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"침울하지 않아요, 사장님.","JPN":"落ち込んでなどいませんわ、社長。","ENG":"I'm not dejected, Boss.","TWN":"我沒有消沉，老闆。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저에게는 그런 감정이 존재하지 않으니까요. 남은 것은 오직 냉철한 이성뿐…….","JPN":"私にはそういった感情は存在しませんの。残っているのは冷徹な理性のみ……","ENG":"Such emotions do not exist within me. All that remains is cold, rational reason...","TWN":"我沒有那種情緒，剩下的只有冷靜的理智……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 어째선지…….","JPN":"だが、なぜか……","ENG":"And yet, for some reason...","TWN":"可是，不知為何……"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나에게는 자네의 감정이 느껴지는군.","JPN":"私には君の感情が伝わってくる。","ENG":"I can sense your emotions.","TWN":"我能感覺到你的情感。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그건 틀림없이 착각이겠죠.","JPN":"それは気のせいですわ。","ENG":"That must surely be a misunderstanding.","TWN":"那一定只是錯覺吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 그 배려가, 조금은 감사할지도 모르겠군요.","JPN":"ですが、その気遣いが少し嬉しいのかもしれません。","ENG":"Still, I may be grateful for the sentiment.","TWN":"不過說不定這份關心令人感謝呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CA_REGINA_PART_B","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"제 걱정은 하실 필요 없습니다, 사장님.","JPN":"私の心配は要りません、社長。","ENG":"There's no need to worry about me, Boss.","TWN":"請不必為我擔心，老闆。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 이곳을 떠나지 않아요. 학회장으로서 제 영지를 지키는 의무를 다해야 하니까.","JPN":"私はここを離れません。学会長として自分の領地を守るという義務を果たさねばなりませんもの。","ENG":"I'm not leaving this place. As President, it is my duty to protect my estate.","TWN":"我不會離開這裡。身為學會長，我必須履行守護領地的義務。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"기다리고 있었답니다, 관리자.","JPN":"待っていました、管理者。","ENG":"I've been waiting for you, Administrator.","TWN":"我一直在等你，管理者。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"극장이로군. 자네에게 무척이나 어울리는 곳이야.","JPN":"劇場か。君にぴったりの場所だと思う。","ENG":"A theater, I see. It suits you very well.","TWN":"是劇場啊，這裡非常適合你呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"후후, 프리마돈나로서 영광이로군요.","JPN":"ふふ、プリマドンナとして光栄ですね。","ENG":"Haha, what an honor for a prima donna.","TWN":"呵呵，作為首席女伶，真是我的榮幸。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"로열 오페라 하우스랍니다. 오늘 공연은 없지만, 이곳의 마지막을 보고 싶었어요.","JPN":"ロイヤルオペラハウスです。今日の上演はありませんが、ここの最後の景色を見ておきたかったのです。","ENG":"It's the Royal Opera House. There's no performance today, but I wanted to see its final moments.","TWN":"這是皇家歌劇院。今天雖然沒有演出，但我想再看這裡最後一眼。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"머지않아, 대균열의 뿌리가 이곳을 뒤덮게 될 테니까요.","JPN":"まもなく大亀裂の根に覆い尽くされてしまうでしょうから。","ENG":"Before long, the roots of the Grand Dimension Crevice will cover this place as well.","TWN":"因為不久之後，大峽谷的根就會覆蓋這裡。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"자네가 보낸 팬레터는 잘 읽어보았네.","JPN":"君からのファンレターは読ませてもらったよ。","ENG":"I read the fan letter you sent quite carefully.","TWN":"我已經仔細讀過你寄來的粉絲信了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그 편지가 도움이 되었다면 다행이네요.","JPN":"役に立てたなら何よりです。","ENG":"I'm glad to hear it was of some help.","TWN":"那封信能派上用場，真是太好了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 각본대로, 학회와 교단 양쪽 모두 클리포트 게임에 간섭할 수 없겠지.","JPN":"君の脚本通り、学会と教団どちらもクリフォトゲームには干渉できないだろう。","ENG":"Just as you scripted it, neither the Society nor the faction will be able to interfere with the Qliphoth Game.","TWN":"照你的劇本，學會與教團雙方應該都無法再干涉逆卡巴拉遊戲。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"또한 은밀하게 전조 현상에 관여한 세력에 관해서도 짐작할 수 있었어.","JPN":"それに、密かに前兆現象に関わっている勢力についても見当がついた。","ENG":"And I was also able to infer the forces that were secretly involved in accelerating the omen phenomenon.","TWN":"同時也能推測出暗中介入前兆現象的勢力。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 자네의 각본으로 인해, 우리가 잃어버린 것도 있다네.","JPN":"しかし君の脚本によって我々が失ったものもある。","ENG":"However, because of your script, there were things we lost as well.","TWN":"但因為你的劇本，我們也失去了某些東西。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"관리국은 샤레이드를 잃어버렸고…….","JPN":"管理局はシャレードを失い……","ENG":"The Administration lost Charade...","TWN":"管理局失去了查雷德……"},"stage":{"bg":"OMEN_CHARADE_01","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"한 소녀는 자신의 평범한 인생을 잃어버렸으며…….","JPN":"ある少女は己の平凡な人生を失い……","ENG":"One girl lost her ordinary life...","TWN":"一名少女失去了她原本平凡的人生……"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다른 소녀는 자신의 영지 대부분을 잃어야만 했네.","JPN":"またある少女は己の領地のほとんどを失った。","ENG":"And another girl was forced to lose most of her estate.","TWN":"另一名少女，則失去了自己大半的領地。"},"stage":{"bg":"BLACK","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 각본에 휘말려버린 이들을, 자네는 어떻게 생각하지?","JPN":"君の脚本に巻き込まれてしまった者たちについて、君はどう思っている？","ENG":"What do you think of those who were swept up in your script?","TWN":"對於被捲入你劇本中的那些人，你又有什麼想法呢？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"글쎄요, 그건 굉장히 당신답지 않은 이야기로군요.","JPN":"さあ、それはあなたらしくない話ですね。","ENG":"Well, that's a surprisingly uncharacteristic question coming from you.","TWN":"這真的很不像你會說的話呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"구할 수 있는 것에 비해, 잃는 것이 무척 적은… 최선의 각본이었다고 생각해요.","JPN":"救えるものに比べ、失うものは極端に少ない……最善の脚本だったと思います。","ENG":"Compared to what could have been saved, what was lost was very little... I believe it was the best possible script.","TWN":"相較於能拯救的事物，失去的已經少到極致了……我認為那是最好的劇本。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"당신이라면 분명 이해하겠죠, 존 스미스?","JPN":"あなたならきっと理解してくれますよね？　ジョン・スミス。","ENG":"Someone like you would surely understand, wouldn't you, John Smith?","TWN":"你一定能理解吧，約翰．史密斯？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"존 스미스라…….","JPN":"ジョン・スミスか……","ENG":"John Smith...","TWN":"約翰．史密斯啊……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 모습을 보니, 자네는 자신의 이야기를 끝마친 모양이군.","JPN":"その様子を見ると、君は自分の物語に幕を下ろしたようだな。","ENG":"Seeing you now, it seems you have brought your own story to its end.","TWN":"看來，你已經為自己的故事畫下句點了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그런 과격한 방식으로는 언젠가 후회하게 될 지도 모르지.","JPN":"だがそういう過激なやり方では、いつか後悔することになるかもしれない。","ENG":"But such a drastic approach may leave you with regrets someday.","TWN":"不過你用這麼激進的方式，說不定總有一天會後悔呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 것을 구하려다가 그 무엇도 구하지 못한 무책임한 남자, 존 스미스처럼 말이야.","JPN":"すべてを救おうとして何一つ救えなかった無責任な男、ジョン・スミスのようにね。","ENG":"Just like John Smith, the irresponsible man who tried to save everything and ended up saving nothing.","TWN":"就像那個想拯救一切，卻什麼也救不了、不負責任的男人約翰．史密斯一樣。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"엄밀히 말하자면, 당신과 저는 초면이지만…….","JPN":"厳密に言うと、私があなたに会うのは初めてですが……","ENG":"Strictly speaking, you and I are meeting for the first time...","TWN":"雖然嚴格來說，我們是初次見面……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"당신에 관해서라면, 그녀의 기억과 그곳의 테라브레인을 통해서 충분히 알고 있어요.","JPN":"あなたのことは、彼女の記憶とテラブレインを通してよく知っています。","ENG":"But when it comes to you, I know more than enough through her memories and the Terrabrain there.","TWN":"但我早已透過她的記憶以及那裡的特拉大腦充分了解你的事。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"당신이 그동안 얼마나 무수한 실패 끝에, 지금의 세계에 다다랐는지.","JPN":"あなたが今までどれだけの失敗を重ねた末に、今の世界にたどり着いたのか。","ENG":"I know how you reached this world after countless failures.","TWN":"你經歷了多少次失敗，才抵達現在這個世界。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"당신이 그동안 얼마나 간절한 마음으로, 이 세계를 지키려고 하는지.","JPN":"あなたが今までどれだけ切実な気持ちで、この世界を守ろうとしているのか。","ENG":"I know how desperately you've tried to protect this world all this time.","TWN":"你懷抱多麼迫切的心情，試圖守護這個世界。"},"stage":{"bg":"MAINSTREAM_003024","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"지금의 저라면, 이해할 수 있겠죠.","JPN":"今の私なら、理解できます。","ENG":"The current me can understand that.","TWN":"現在的我，應該能理解了。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그러니까 이 각본은 제 나름대로 당신에 대한 응원이랍니다.","JPN":"だから、この脚本はあなたに対する私なりの応援なのです。","ENG":"That's why this script is my own way of cheering you on.","TWN":"所以這份劇本是我對你的支持。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"팬이니까요, 당신의.","JPN":"ファンですから。あなたの。","ENG":"I'm your fan.","TWN":"我是你的粉絲。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CITY_CHARADE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};